sql:
SELECT SUM(grants.amount_sanctioned) AS total_amount_sanctioned_2015
FROM grants
WHERE grants.financial_year = 2015;

SELECT * 
FROM grants
WHERE grant_id NOT IN (SELECT grant_id FROM grant_utilization);

external_knowledge:
- "dipped their toes into the grant pool" refers to utilizing grants;
- "most recent splash dates" refers to the latest utilization dates;
- "amount of water they drew from the pool" refers to the amount utilized from the grant.

sql:
SELECT department_name, email, phone_number, FLOOR(department_id) AS floored_department_id, RANK() OVER (ORDER BY department_id) AS rank
FROM departments
WHERE department_id > 5;

external_knowledge:
- "funding" refers to the allocation of grants;
- "sent in applications" implies the department has records in the `grant_applications` table;
- "haven't received any" means there are no corresponding records in the `grant_allocations` table for those applications.

sql:
SELECT department_name 
FROM departments 
WHERE department_id IN (SELECT department_id FROM grant_applications WHERE status = 'submitted');

SELECT grant_id, SUM(amount_allocated) AS Total_Amount_Allocated 
FROM grant_allocations 
GROUP BY grant_id;
